var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 다들 화면에 집중하세요.","JPN":"次は画面をご覧ください。","ENG":"Okay everyone, now focus on the screen.","TWN":"來，大家集中看畫面。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"총기 안전장치 관리를 소홀히 했다가 부상 입은 사례입니다. 사건 발생 개요부터 살펴 보자면......","JPN":"銃器の安全装置の管理を怠り、負傷に繋がった事例です。事件の発生概要については……","ENG":"This case of injury is from a negligent discharge of a firearm. It happened...","TWN":"這是因疏忽槍枝安全裝置管理而受傷的案例。從事件發生的概要來看的話…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"할아버지, 이거 자장가 맞지?","JPN":"おじいちゃん、これ子守歌だよね？","ENG":"Grandpa, doesn't this sound like a lullaby to you?","TWN":"爺爺，這是搖籃曲吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"으음......! 그래! 무시무시한 음파 병기의 일종이 틀림없는 것 같군!","JPN":"うむ……！　どうやら恐ろしい音波兵器のようだな！","ENG":"Mm... It does. It's got to be some sort of sonic wave-based weapon. So terrible!","TWN":"嗯......！對！ 這一定是可怕的音波兵器的一種！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카, 나 너무 졸려...... 교대하자......","JPN":"オルカ、眠すぎる……交代……","ENG":"Orca, I'm so sleepy... Switch with me...","TWN":"奧爾卡，我好睏啊...... 我們輪班吧......"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"지루해서 속이 메스꺼운 적은 오늘이 처음이야......","JPN":"初めてだぜ……退屈すぎて胃もたれするような経験は……","ENG":"I've never experienced anything so nauseatingly boring...","TWN":"今天是第一次感覺到無聊到有點噁心......"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"기어코 여길 끌고 오다니...... 이수연 녀석, 아직도 원한이 덜 풀렸나 보군.","JPN":"とうとう私をここに連れてくるとは……カナミのやつ、まだ恨みが晴れていないようだな。","ENG":"She had to drag me here. Lee Sooyeon's definitely still angry with me.","TWN":"偏偏要把我拉到這裡來……李秀妍這傢伙，看來到現在還沒有完全解恨啊。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배...... 선심 쓰듯이 가라고 하더니 자기만 쏙 빠져 나가고...... 가만 안 둘 줄 알아......","JPN":"先輩……私には行きなさいって言っておいて、\\n自分は逃げ出すなんて……許さない……","ENG":"Shiyoon... He acted as if he was doing me a favor coming here with me, and now he's gone. If I find him, he's a dead man...","TWN":"前輩...... 像發善心一樣讓我走，結果他自己卻溜走了……我不會放過他……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어쩌죠, 부사장님. 이대로라면 절반도 듣기 전에 다들 쓰러지시겠어요.","JPN":"副社長、どうしましょう……まだ半分も終わってないのにみんな倒れそうな勢いです。","ENG":"Vice President, what do we do? At this rate, everyone's going to fall asleep before we even finish the first half.","TWN":"怎麼辦，副總。 照這樣下去，在聽到一半之前，大家都會暈倒的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 제대로 안 들으면 재이수라고 했는데도 이 꼴이군요.","JPN":"まったく、ちゃんと聞かないと再履修だって伝えたのに、この調子だなんて。","ENG":"I know. I even told them they'd have to take it again if they didn't pay attention.","TWN":"對，如果不乖乖聽的話，會再進修，但還真是這樣。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그나저나 사장님도 참 대단하시네요. 아까부터 불평 한마디 안 하고 들으시잖아요.","JPN":"だけど社長はすごいですね！\\n文句の一言も言わず、しっかり聞いています。","ENG":"By the way, the Boss is doing incredibly well. He hasn't complained at all since we began.","TWN":"話說回來，老闆也真了不起。因為從剛才開始一句怨言都沒有。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"글쎄요. 제 눈에는 그냥 절전 모드인 걸로 보입니다만.","JPN":"そうですね……私には省エネモードに入ってるように見えますが。","ENG":"I don't know. To me, he looks like he's in sleep mode.","TWN":"這個嘛，在我看來，這只是一種省電模式罷了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>편의점 아포칼립스 코핀 컴퍼니 지점</color>에서 <color=#ffd34c>어린이 요리 도구 세트</color> 2개 결재가 완료되었습니다.","JPN":"<color=#ffd34c>コンビニエンスストア[アポカリプス]コフィンカンパニー支店</color>で<color=#ffd34c>子どもクッキングセット</color>2個の支払いが完了しました。","ENG":"Two <color=#ffd34c>Children's Cooking Utensil Sets</color> have been purchased at the <color=#ffd34c>Apocalypse convenience store Coffin Company branch</color>.","TWN":"在<color=#ffd34c>便利商店阿波卡利斯科芬公司分店</color>支付了兩個 <color=#ffd34c>兒童料理道具組合</color>。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"대금은 회사로 청구됩니다. 하. 하. 하.","JPN":"代金は会社へ請求されます。はっ・はっ・は。","ENG":"They've been charged on the company credit card. Hah. Hah. Hah.","TWN":"費用會向公司請款。哈. 哈. 哈."},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"거기! 집중 안 하시면 교육 연장 합니다!","JPN":"そこ！　集中しないと研修を延長しますよ！","ENG":"Excuse me! Stay focused, or the class will be extended!","TWN":"那邊！如果不集中的話課程會延長喔！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 네! 죄송합니다!","JPN":"あっ、はい！　すみません……！","ENG":"Oops, sorry!","TWN":"啊，好！對不起！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"......"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 사람 회사에서 혼자 무슨 짓을 하는 거람......?","JPN":"あの人、会社で一人で何をしてるの……？","ENG":"What the hell is he doing alone at the company?","TWN":"這個人在公司一個人在幹什麼呢......？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자, 이번 숙제는 요리란다.","JPN":"さあ、今回の宿題はお料理だ。","ENG":"Now, your task this time is cooking.","TWN":"來，這次的功課是料理。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"아인, 요리가 뭐야?","JPN":"お料理……？アイン、お料理ってなぁに？","ENG":"Eins, what's cooking?","TWN":"艾茵，什麼叫料理？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"요리는 맛있는 걸 만드는 일이야. 연구소로 가기 전에 몇 번 본 적 있어.","JPN":"お料理は、おいしいものを作ることよ。研究所へ行く前に、何回か見たことがあるわ。","ENG":"It's making food. I'd seen people cook before we were sent to the lab.","TWN":"料理是做好吃的工作，我去研究所前有看過幾次。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"맛있는 걸 만들어? 진짜?","JPN":"おいしいものを作る？　そんなことができるの？","ENG":"Making food? Really?","TWN":"做好吃的？真的？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"연구소 어른들이 주던 건 전부 튜브에 들어 있었는데......?","JPN":"食べ物って、チューブに入ってるものじゃないの……？　だって研究所の大人たちはみんな……","ENG":"Everything that the lab people fed us was in a tube.","TWN":"研究所大人們給的都是裝在軟管裡的......？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"그러게 내가 말했잖아. 바깥에는 재미난 것도 맛있는 것도 무지 많다고.","JPN":"だから言ったじゃない。外の世界には楽しいこともおいしいものもい～っぱいあるんだって。","ENG":"I told you. There are lots of interesting and delicious things outside the lab.","TWN":"所以我不是說過了嗎？外面有很多好玩和好吃的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"응, 무지무지 많아~","JPN":"本当だね！　い～っぱいある！","ENG":"Yes, there are so many of them.","TWN":"嗯，真的很多~"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"......"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아인 말이 맞단다. 요리를 할 줄 알면 자기가 먹고 싶은 음식도 언제든 만들 수 있지.","JPN":"アインのいうとおりだ。お料理ができるようになると、いつでも食べたいものを作れるんだよ。","ENG":"Eins is right. If you know how to cook, you can cook whatever you want anytime you want.","TWN":"艾茵說的對！如果會做料理隨時都可以做自己想吃的東西。"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자, 그럼 바로 시작해 볼까? 불을 쓸 때는 꼭 나한테 얘기해야 된다?","JPN":"早速始めてみようか。火を使うときは先に言ってくれよ？","ENG":"Okay, then let's get started, shall we? Don't forget to tell me before you use the stove, okay?","TWN":"好，那我們馬上開始吧？ 用火的時候一定要告訴我？"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHILDREN_BARCODE_NULL_NULL","text":{"KOREA":"네에~!","JPN":"は～い！","ENG":"Okie!","TWN":"是~！"},"stage":{"bg":"OFFICE","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오, 아인은 베이컨도 구울 줄 아는구나?","JPN":"ほう、アインはベーコンが焼けるんだな。","ENG":"Ooo, Eins, you know how to cook bacon.","TWN":"喔，艾茵還會煎培根啊？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"응. 여기다가 계란 프라이를 만들면 더 맛있어. 연구소 가기 전에 엄마가 하는 걸 봤거든.","JPN":"うん！　これに目玉焼きを添えたらもっとおいしくなるよ！\\n研究所に行く前に、ママがやってるのを見たの。","ENG":"Yes. It's more delicious when you eat it with fried eggs. I saw Mom cook them before I was sent to the lab.","TWN":"嗯，在這裡做煎蛋會更好吃。去研究所之前，我看過媽媽做的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음...... 아인은 엄마를 다시 만나고 싶진 않니?","JPN":"なるほどね……アインはお母さんに会いたくないかい？","ENG":"Hmm... Eins, don't you want to see your mom?","TWN":"嗯...... 艾茵不想再見到媽媽嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"가도 안 만나 줄 걸.","JPN":"会いに行っても、会ってもらえないとおもうよ。","ENG":"Even if I do, she won't see me.","TWN":"去了也不會見我的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"엄마랑 아빤 시계에서 빛이 나온다고 하자마자 날 팔아치웠으니까.","JPN":"パパとママ、時計から放つ光を見てすぐわたしを研究所に売ったからね。","ENG":"Mom and Dad sold me as soon as they saw my Watch glow.","TWN":"因爲爸爸和媽媽一聽到手錶發光就把我賣了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"그래도 괜찮아. 언니가 반군 아저씨들이랑 있는 것보단 연구소가 더 좋댔거든.","JPN":"でも、大丈夫よ。反乱軍のおじさんたちといるよりは研究所のほうがいいって、お姉ちゃんも言ってたし。","ENG":"But that's okay. Sister said I was better off staying at the lab than with those rebels.","TWN":"不過也沒關係，姐姐說比起和叛軍叔叔們在一起，待在研究所更好。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"......"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"오빠~ 큰일났어~","JPN":"お兄ちゃ～ん！　大変～！","ENG":"Brother, I've got a problem!","TWN":"哥哥~ 出大事了~"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 왜 그러니, 츠바이?","JPN":"ツヴァイ、どうした？","ENG":"Mm? What's wrong, Zwei?","TWN":"嗯？怎麼了，茨粨？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"튜브가 없어~","JPN":"チューブがないよ～。","ENG":"I don't have a tube.","TWN":"軟管不見了~"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"입에 물고 쭉~ 짜면 안에서 먹을 게 나오는 거 있잖아.","JPN":"食べ物を入れてチューチュー吸うあれがないの。","ENG":"You know, the tube that you can hold between your teeth and squeeze upward to eat what's inside.","TWN":"含在嘴裡~ 不是擠一下就會有吃的東西嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우주 식량 말이구나. 여기선 그렇게 먹지 않아도 된단다.","JPN":"宇宙食のことかな？　ここではそんなふうに食べなくてもいいんだよ。","ENG":"You mean, astronaut food. You don't have to eat like that here.","TWN":"是宇宙糧食啊，在這裡可以不用那樣吃。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"어? 그럼 먹을 건 어떻게 만들어?","JPN":"え～？　じゃあ、どうやって食べ物を作ればいいの……？","ENG":"Huh? Then how do we eat here?","TWN":"咦？那麼要怎麼做吃的？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 츠바이는 먼저 자기가 뭘 좋아하는지부터 알아야겠구나.","JPN":"やれやれ、ツヴァイはまず自分の好きな食べ物を見つけないといけないね。","ENG":"Oh, Zwei. Perhaps you should first find out what you like to eat.","TWN":"哎呀，茨粨應該先知道自己喜歡什麼。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나랑 같이 찾아 볼까? 예전에 먹어 본 것 중에 기억나는 맛은 없니?","JPN":"一緒に見つけようか？\\n昔食べたものの中で記憶に残ってるものはないかい？","ENG":"How about we find out together? Do you remember any specific flavor that you tried before?","TWN":"要和我一起找找看嗎？以前吃過的東西裡面有沒有記得的味道？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"기억나는 맛~ 기억나는 맛~","JPN":"記憶に残ってるもの……記憶に……","ENG":"Any specific flavor... Any specific flavor...","TWN":"記得的味道~ 記得的味道~"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"아, 맞다! 처음으로 테스트 끝나고 먹은 특식이 제일 맛있었어!","JPN":"そうだ、初めてのテストが終わった日に食べた特別食が一番おいしかったよ！","ENG":"Ooh, right! I loved that special food that they gave me after my first test!","TWN":"啊，對了！第一次測試結束後吃的特餐覺得最好吃！ "},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"테스트?","JPN":"テスト？","ENG":"What test?","TWN":"測試？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"응. 유리관에서 나온 다음부터 날마다 했거든.","JPN":"うん！　試験管を出てからは毎日してたんだ。","ENG":"They tested me every day since I came out of the test tube.","TWN":"嗯，自從玻璃管出來以後，每天都做了。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"으음~ 그러니까~","JPN":"えっとね～それから……","ENG":"Mm, so...","TWN":"嗯~ 就是說啊~"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};